from typing import Any


COARSE_STATUSES = {"todo", "ready", "in_progress", "blocked", "review", "qa", "done"}
STAGE_LIKE_STATUSES = {"planned", "approved", "archived"}
MUTATING_SHELL_TOKENS = (
    '"sed *": allow',
    '"gofmt',
